%[text] # validate\_params (Live Script)
%[text] Simula a planta com `P_J` fornecido em UMA OU MAIS janelas do log e gera comparações nos 3 modos (full, hybrid, semi).
%[text] **NÃO RODA OTIMIZAÇÃO** — só simula. Útil pra testar P0, P\_final, ou mudanças manuais (ex: Jy do slide, Bz=0, etc) lado a lado em várias janelas.
%[text] Outputs: figuras em `outputs/images/` com prefixo `VP_<tag>_w<n>_<modo>.png` + tabela comparativa de R² no console no fim.

clear; clc; close all;
addpath(fileparts(fileparts(mfilename('fullpath'))));
setup_paths();

%%
%[text] ## 1. Log a usar
%[text] `LOG_FILE` pode ser o concatenado (gerado por `test_flight.m`) ou um log individual.

LOG_FILE = 'logs_concat.mat';

%%
%[text] ## 2. Janelas de validação
%[text] Cada **linha** da matriz é uma janela `[t_start, t_end]` em segundos do log. Pode ser uma janela (1×2) ou várias (N×2).

T_WINDOWS = [ ...
%    1, 45];


%    75, 110]; %validar Y
%    55, 80];  %validar X
   370, 380];  %validar X

%%
%[text] ## 3. Modos de simulação
%[text] - `full`: integra tudo (pqr + Euler + translacional)
%[text] - `hybrid`: integra pqr + translacional, usa atitude medida (EKF)
%[text] - `semi`: usa pqr medido + atitude medida, só integra translacional \

RUN_FULL   = true;
RUN_HYBRID = false;
RUN_SEMI   = false;

%%
%[text] ## 4. Linhas dos plots
%[text] Cada flag ativada vira **uma linha de 3 colunas** na figura (X/Y/Z). Ative só o que interessa.
%[text] - `PLOT_PQR`     → p, q, r (medido vs sim)
%[text] - `PLOT_MOMENTS` → Mx, My, Mz (só sim — não há sensor de torque)
%[text] - `PLOT_ATT`     → phi, theta, psi (medido vs sim)
%[text] - `PLOT_ACC`     → accX, accY, accZ (medido vs sim) \

PLOT_PQR     = true;
PLOT_MOMENTS = false;
PLOT_ATT     = false;
PLOT_ACC     = true;

%[text] **Colunas** (`PLOT_X`, `PLOT_Y`, `PLOT_Z`): isola eixo. Ex: só Z pra focar em yaw (r, Mz, psi, accZ).

PLOT_X = true;
PLOT_Y = true;
PLOT_Z = true;

%%
%[text] ## 5. Fonte do vetor de parâmetros `P_J`
%[text] Opções: `'P0'` (chute inicial), `'P_final'` (resultado da identificação), `'manual'` (edite `P_MANUAL` abaixo).

P_SOURCE = 'manual';

%%
%[text] ## 6. `P_MANUAL` (15 elementos — modelo rotacional puro)
%[text] Ordem: `[Jx Jy Jz Jxz | k_T1..4 | k_Q1..4 | Dp Dq Dr]`
%[text] **Bp, Bq, Br** REMOVIDOS — CG offset via `Lx_r`/`Lx_l`/`Ly_f`/`Ly_r` assimétricos.
%[text] **Xu, Yv, Zw** REMOVIDOS — drag translacional não-identificável sem GPS velocity.
%[text] **Bz** REMOVIDO — vai pra modelo de sensor (sensor\_bias\_z) depois.

P_MANUAL = [ ...
    0.072; 0.200; 0.150; 0.000933;    ... % Jx Jy Jz Jxz
    0.71; 0.71; 0.66; 0.67;            ... % k_T1..4
    0.79; 0.79; 0.87; 0.86;        ... % k_Q1..4
    1.27; 1.27; 0.47];                 % Dp Dq Dr

%%
%[text] ## 7. Tag de saída
%[text] Sufixo nos nomes de arquivo, pra distinguir testes.

TAG = 'test1';

%%
%[text] ## 8. Validação e carregamento
%[text] Verifica formato da matriz de janelas e carrega P\_J e log.

if size(T_WINDOWS, 2) ~= 2
    error('T_WINDOWS deve ser Nx2 (cada linha = [t_start, t_end]). Recebeu %dx%d.', size(T_WINDOWS));
end
n_wins = size(T_WINDOWS, 1);

proj = parameters();
switch lower(P_SOURCE) %[output:group:7027f617]
    case 'p0'
        P_J = proj.P0_J;
        fprintf('validate_params: usando P0 (chute inicial).\n');
    case 'p_final'
        Pdat = load(fullfile(setup_paths().outputs, 'P_identified.mat'));
        P_J = Pdat.P_final;
        fprintf('validate_params: usando P_final de P_identified.mat.\n');
    case 'manual'
        P_J = P_MANUAL(:);
        fprintf('validate_params: usando P_MANUAL.\n'); %[output:1214b0c7]
    otherwise
        error('P_SOURCE inválido: %s', P_SOURCE);
end %[output:group:7027f617]
if numel(P_J) ~= 15
    error('P_J deve ter 15 elementos. Recebeu %d.', numel(P_J));
end

log_path = fullfile(setup_paths().data, LOG_FILE);
if ~exist(log_path, 'file')
    fprintf('⚠ Arquivo "%s" não encontrado.\n', LOG_FILE);
    fprintf('  Para usá-lo, rode primeiro: >> test_flight\n');
    fprintf('  Usando log individual como fallback.\n\n');
    LOG_FILE = '4 25-05-2026 09-31-48.log-132954.mat';
    log_path = fullfile(setup_paths().data, LOG_FILE);
end
L = load_log_data(log_path); %[output:99535a65]
t_lo = max([min(L.time_IMU), min(L.time_ATT), min(L.time_RCOU)]);
t_hi = min([max(L.time_IMU), max(L.time_ATT), max(L.time_RCOU)]);
t_common_full = (t_lo:0.1:t_hi)';

constants = struct('m', proj.m, 'g', proj.g, 'tau_motor', proj.tau_motor);
R2 = @(y_e, y_s) 1 - sum((y_e - y_s).^2) / max(sum((y_e - mean(y_e)).^2), 1e-12);

modes = {};
if RUN_FULL,   modes{end+1} = 'full';   end
if RUN_HYBRID, modes{end+1} = 'hybrid'; end
if RUN_SEMI,   modes{end+1} = 'semi';   end

sig_names = {'p','q','r','phi','theta','psi','accX','accY','accZ'};
R2_table = nan(n_wins, numel(modes), numel(sig_names));

img_dir = setup_paths().images;
if ~exist(img_dir, 'dir'), mkdir(img_dir); end

%%
%[text] ## 9. Loop sobre janelas: simulação + R² + plots
%[text] Pra cada janela: recorta sinais, roda modos selecionados, calcula R² por sinal, gera figuras.

for w = 1:n_wins %[output:group:66834340]
    t_window = T_WINDOWS(w, :);
    fprintf('\n############### JANELA %d/%d: [%.1f, %.1f] s ###############\n', ... %[output:637ee414]
        w, n_wins, t_window(1), t_window(2)); %[output:637ee414]

    if t_window(1) < t_lo || t_window(2) > t_hi
        warning('Janela [%g, %g] fora do log [%.1f, %.1f] — PULANDO', ...
            t_window(1), t_window(2), t_lo, t_hi);
        continue;
    end

    idx = (t_common_full >= t_window(1)) & (t_common_full <= t_window(2));
    time = t_common_full(idx);
    N = numel(time);

    pwm      = [interp1(L.time_RCOU, L.pwm1_raw, time, 'linear'), ...
                interp1(L.time_RCOU, L.pwm2_raw, time, 'linear'), ...
                interp1(L.time_RCOU, L.pwm3_raw, time, 'linear'), ...
                interp1(L.time_RCOU, L.pwm4_raw, time, 'linear')];
    pqr_meas = [interp1(L.time_IMU, L.gyrX_raw, time, 'linear'), ...
                interp1(L.time_IMU, L.gyrY_raw, time, 'linear'), ...
                interp1(L.time_IMU, L.gyrZ_raw, time, 'linear')];
    acc_meas = [interp1(L.time_IMU, L.accX_raw, time, 'linear'), ...
                interp1(L.time_IMU, L.accY_raw, time, 'linear'), ...
                interp1(L.time_IMU, L.accZ_raw, time, 'linear')];
    att_meas = [interp1(L.time_ATT, L.roll_deg,  time, 'linear'), ...
                interp1(L.time_ATT, L.pitch_deg, time, 'linear'), ...
                interp1(L.time_ATT, L.yaw_deg,   time, 'linear')];

    fprintf('  (%d amostras, dt=%.3f s)\n', N, time(2)-time(1)); %[output:086e0e9e]

    results = struct();
    for k = 1:numel(modes)
        mode = modes{k};
        fprintf('\n  ===== modo: %s =====\n', mode); %[output:7794a3c5]
        tic;
        results.(mode) = sim_window(mode, P_J, time, pwm, pqr_meas, att_meas, constants); %[output:585153d3]
        fprintf('    Tempo sim: %.2f s\n', toc); %[output:4474ad1f]

        r = results.(mode);
        all_meas = {pqr_meas(:,1), pqr_meas(:,2), pqr_meas(:,3), ...
                    att_meas(:,1), att_meas(:,2), att_meas(:,3), ...
                    acc_meas(:,1), acc_meas(:,2), acc_meas(:,3)};
        all_sim  = {r.p, r.q, r.r, r.phi, r.theta, r.psi, r.accX, r.accY, r.accZ};
        for s = 1:9
            R2_table(w, k, s) = R2(all_meas{s}, all_sim{s});
        end
        % Formato idêntico ao identify_plant.m → print_R2
        fprintf('  [%s] Validação (%g-%gs):\n', mode, t_window(1), t_window(2)); %[output:118f2e20]
        fprintf('    R² p=%.4f | q=%.4f | r=%.4f\n', ... %[output:3cc421fc]
            R2_table(w,k,1), R2_table(w,k,2), R2_table(w,k,3)); %[output:3cc421fc]
        fprintf('    R² AccX=%.4f | AccY=%.4f | AccZ=%.4f\n', ... %[output:3b03cc57]
            R2_table(w,k,7), R2_table(w,k,8), R2_table(w,k,9)); %[output:3b03cc57]
    end

    plot_rows = {};
    if PLOT_PQR,     plot_rows{end+1} = 'pqr';     end
    if PLOT_MOMENTS, plot_rows{end+1} = 'moments'; end
    if PLOT_ATT,     plot_rows{end+1} = 'att';     end
    if PLOT_ACC,     plot_rows{end+1} = 'acc';     end

    plot_cols = [];   % índices das colunas (1=X, 2=Y, 3=Z)
    if PLOT_X, plot_cols(end+1) = 1; end
    if PLOT_Y, plot_cols(end+1) = 2; end
    if PLOT_Z, plot_cols(end+1) = 3; end

    if isempty(plot_rows) || isempty(plot_cols)
        warning('Nenhuma linha ou coluna selecionada (PLOT_*). Pulando plots.');
    else
        for k = 1:numel(modes)
            mode = modes{k};
            r = results.(mode);
            plot_compare_rows(time, mode, TAG, w, t_window, plot_rows, plot_cols, ... %[output:0b3a5021]
                pqr_meas, att_meas, acc_meas, r, img_dir); %[output:0b3a5021]
        end
        if numel(modes) > 1
            plot_modes_overlay_rows(time, modes, results, plot_rows, plot_cols, ...
                pqr_meas, att_meas, acc_meas, TAG, w, t_window, img_dir);
        end
    end
end %[output:group:66834340]

%%
%[text] ## 10. Tabela comparativa final de R²
%[text] R² por sinal × janela × modo. Útil pra ver se o ajuste é consistente entre trechos diferentes do voo.

fprintf('\n\n');
fprintf('═══════════════════════════════════════════════════════════════════\n'); %[output:76eb9de2]
fprintf('  TABELA COMPARATIVA DE R² — todas as janelas / modos / sinais\n'); %[output:2d08bfc4]
fprintf('═══════════════════════════════════════════════════════════════════\n'); %[output:65d7bf60]
for s = 1:numel(sig_names) %[output:group:8a7e0d71]
    fprintf('\n  %s:\n', sig_names{s}); %[output:5dbb9adc] %[output:2d94ae43] %[output:12f689bb] %[output:701b9c00] %[output:93969080] %[output:0f9d1cd6] %[output:8b406d46] %[output:16643290] %[output:4ddee8d0]
    fprintf('    %-12s', 'janela'); %[output:7b5aa56d] %[output:0fbfb657] %[output:2cd1756d] %[output:614bfd9d] %[output:1d4d9e21] %[output:48f4988e] %[output:1a93a788] %[output:8a16792a] %[output:69e9f5e9]
    for k = 1:numel(modes), fprintf(' %10s', modes{k}); end %[output:06ac9133] %[output:1ed8862a] %[output:19bd67a5] %[output:9790f63b] %[output:6f653b74] %[output:6c7c1aa6] %[output:530993be] %[output:69391b80] %[output:6b0df600]
    fprintf('\n');
    for w = 1:n_wins
        fprintf('    [%4.0f,%4.0f] ', T_WINDOWS(w,1), T_WINDOWS(w,2)); %[output:7de5521b] %[output:9ca2100f] %[output:980380bf] %[output:316d2dc7] %[output:1fda53c7] %[output:9048c581] %[output:6cadfc41] %[output:3588ba77] %[output:2a56acae]
        for k = 1:numel(modes)
            fprintf(' %+10.3f', R2_table(w, k, s)); %[output:8b1abccb] %[output:76d6a7e2] %[output:4c638b78] %[output:54590a2c] %[output:298f6653] %[output:6ff5783f] %[output:9a117508] %[output:5714595c] %[output:01728831]
        end
        fprintf('\n');
    end
end %[output:group:8a7e0d71]
fprintf('\n═══════════════════════════════════════════════════════════════════\n'); %[output:8bd27268]
fprintf('Figuras salvas em: %s\n', img_dir); %[output:90850714]

%%
%[text] ## Helpers (não precisa editar abaixo)

function [labels, units, meas_cell, sim_cell, has_meas, ylims] = row_signals(row_type, ...
    pqr_m, att_m, acc_m, r)
    switch row_type
        case 'pqr'
            labels = {'p','q','r'};
            units  = {'rad/s','rad/s','rad/s'};
            meas_cell = {pqr_m(:,1), pqr_m(:,2), pqr_m(:,3)};
            sim_cell  = {r.p, r.q, r.r};
            has_meas = true;
            ylims = {[-4 4], [-4 4], [-1.2 1.2]};
        case 'moments'
            labels = {'Mx','My','Mz'};
            units  = {'N·m','N·m','N·m'};
            meas_cell = {[], [], []};
            sim_cell  = {r.Mx, r.My, r.Mz};
            has_meas = false;
            ylims = {[-3 3], [-3 3], [-0.3 0.3]};
        case 'att'
            labels = {'phi','theta','psi'};
            units  = {'deg','deg','deg'};
            meas_cell = {att_m(:,1), att_m(:,2), att_m(:,3)};
            sim_cell  = {r.phi, r.theta, r.psi};
            has_meas = true;
            ylims = {[], [], []};
        case 'acc'
            labels = {'accX','accY','accZ'};
            units  = {'m/s²','m/s²','m/s²'};
            meas_cell = {acc_m(:,1), acc_m(:,2), acc_m(:,3)};
            sim_cell  = {r.accX, r.accY, r.accZ};
            has_meas = true;
            ylims = {[], [], []};
        otherwise
            error('row_type desconhecido: %s', row_type);
    end
end

function plot_compare_rows(time, mode, tag, w_idx, t_win, plot_rows, plot_cols, ...
    pqr_m, att_m, acc_m, r, img_dir)
    n_rows = numel(plot_rows);
    n_cols = numel(plot_cols);
    % 'Visible','on' → mostra figura inline no Live Script (sem close no fim)
    width = 500*n_cols;
    fig = figure('Position', [80 50 width 300*n_rows], 'Color', 'w', 'Visible', 'on');
    for ri = 1:n_rows
        [labels, units, meas, sim, has_meas, ylims] = row_signals(plot_rows{ri}, ...
            pqr_m, att_m, acc_m, r);
        for ci = 1:n_cols
            c = plot_cols(ci);   % índice real da coluna (1=X, 2=Y, 3=Z)
            subplot(n_rows, n_cols, (ri-1)*n_cols + ci); hold on; grid on;
            if has_meas
                plot(time, meas{c}, 'b-',  'LineWidth', 1.0, 'DisplayName', 'medido');
            end
            plot(time, sim{c},  'r--', 'LineWidth', 1.3, 'DisplayName', 'sim');
            title(labels{c}, 'FontWeight', 'bold');
            xlabel('t [s]'); ylabel(units{c});
            if ~isempty(ylims{c}), ylim(ylims{c}); end
            if ri == 1 && ci == 1, legend('Location','best'); end
        end
    end
    sgtitle(sprintf('validate\\_params — modo %s — w%d [%g, %g]s — tag %s', ...
        mode, w_idx, t_win(1), t_win(2), tag));
    saveas(fig, fullfile(img_dir, sprintf('VP_%s_w%d_%s.png', tag, w_idx, mode)));
    % NÃO fecha — fica visível no Live Script + janela MATLAB
end

function plot_modes_overlay_rows(time, modes, results, plot_rows, plot_cols, ...
    pqr_m, att_m, acc_m, tag, w_idx, t_win, img_dir)
    n_rows = numel(plot_rows);
    n_cols = numel(plot_cols);
    width = 500*n_cols;
    fig = figure('Position', [80 50 width 300*n_rows], 'Color', 'w', 'Visible', 'on');
    color_map = containers.Map({'full','hybrid','semi'}, {'r--','m-.','b:'});
    ref_r = results.(modes{1});
    for ri = 1:n_rows
        [labels, units, meas, ~, has_meas, ylims] = row_signals(plot_rows{ri}, ...
            pqr_m, att_m, acc_m, ref_r);
        for ci = 1:n_cols
            c = plot_cols(ci);
            subplot(n_rows, n_cols, (ri-1)*n_cols + ci); hold on; grid on;
            if has_meas
                plot(time, meas{c}, 'Color', [0 0.7 0.3], 'LineWidth', 1.2, ...
                    'DisplayName', 'medido');
            end
            for m = 1:numel(modes)
                rm = results.(modes{m});
                [~, ~, ~, sim_m, ~, ~] = row_signals(plot_rows{ri}, ...
                    pqr_m, att_m, acc_m, rm);
                plot(time, sim_m{c}, color_map(modes{m}), 'LineWidth', 1.2, ...
                    'DisplayName', modes{m});
            end
            title(labels{c}, 'FontWeight','bold');
            xlabel('t [s]'); ylabel(units{c});
            if ~isempty(ylims{c}), ylim(ylims{c}); end
            if ri == 1 && ci == 1, legend('Location','best'); end
        end
    end
    sgtitle(sprintf('validate\\_params — overlay — w%d [%g, %g]s — tag %s', ...
        w_idx, t_win(1), t_win(2), tag));
    saveas(fig, fullfile(img_dir, sprintf('VP_%s_w%d_overlay.png', tag, w_idx)));
    % NÃO fecha — fica visível
end

